with open('data.js', 'r', encoding='utf-8') as f:
    content = f.read()

start_idx = content.find('"acc1":')
if start_idx != -1:
    ch2_idx = content.find('"2":', start_idx)
    if ch2_idx != -1:
        full_cq_idx = content.find('fullCQData: [', ch2_idx)
        if full_cq_idx != -1:
            # We already have CQ1, so we find the closing bracket of fullCQData array
            # But wait, it's safer to just insert after the first element.
            # Let's find the closing bracket of CQ1.
            b_start = content.find('label: "b"', full_cq_idx)
            ans_end = content.find('</div></div>"', b_start) + len('</div></div>"')
            # But there is also part c in CQ1!
            c_start = content.find('label: "c"', b_start)
            c_ans_end = content.find('</div></div>"', c_start) + len('</div></div>"')
            # Find the closing brace '}' of CQ1
            cq1_end = content.find('}', c_ans_end)
            
            # insert our new CQ after this brace
            insert_pos = cq1_end + 1
            new_content = content[:insert_pos] + ",\n" + cq_obj + content[insert_pos:]
            
            with open('data.js', 'w', encoding='utf-8') as f:
                f.write(new_content)
            print("Successfully inserted Chapter 2 CQ 2 into data.js!")
        else:
            print("fullCQData not found in Chapter 2.")
    else:
        print("Chapter 2 not found inside acc1")
else:
    print("acc1 not found")
